import React from 'react';
import optImg from '../assets/opt.jpg';

const Home = () => {
    return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-gray-100">
            {/* Profile Image */}
            <img
                src={optImg}
                alt="Profile"
                className="w-32 h-32 rounded-full mb-6 shadow-lg"
            />
            {/* About Me Section */}
            <h1 className="text-4xl font-bold mb-4">Welcome to My Portfolio</h1>
            <p className="text-lg mb-4 text-center max-w-xl">
                <span className="font-semibold">About Me:</span> <br />
                Hi, I'm Veera! I am a passionate developer with experience in JavaScript, React, Tailwind CSS, and Node.js. I love building modern web applications and learning new technologies.
            </p>
            <h2 className="text-2xl font-semibold mb-2">Skills:</h2>
            <ul className="list-disc list-inside mb-8">
                <li>JavaScript</li>
                <li>React</li>
                <li>Tailwind CSS</li>
                <li>Node.js</li>
            </ul>
            <h2 className="text-2xl font-semibold mb-2">Projects:</h2>
            <p className="mb-4">Check out some of my projects below:</p>
            <a href="/projects" className="text-blue-500 hover:underline">View Projects</a>
        </div>
    );
};

export default Home;
